import{_ as n,c as e,m as s,a as p,t as l,a5 as i,o as r}from"./chunks/framework.DwbewbAn.js";const t="/assets/1460000021464574.lIfAvcig.png",c="/assets/1460000021464573.BErH66cu.png",o="/assets/1460000021464577.CfMb47NU.png",d="/assets/1460000021464578.Ck4sMQjR.png",h="/assets/1460000021464576.CqdlY5G4.png",m="/assets/1460000021464575.Drgz3yQO.png",b="/assets/1460000021464579.D9yFX0ls.png",u="/assets/1460000021464580.B57dI4kW.png",g="/assets/1460000021464581.CLsqVDyc.png",v="/assets/1460000021464584.BSwMpxzF.png",_="/assets/1460000021464582.Dks18AHP.png",k="/assets/1460000021464583.Dn8PQZkc.png",y="/assets/1460000021464588.BKispr5Q.png",f="/assets/1460000021464586.DAtYrmQH.png",w="/assets/1460000021464587.RAFOM7hI.png",x="/assets/1460000021464585.Bvz-bSoq.png",C="/assets/1460000021464590.Db2_THDd.png",q="/assets/1460000021464591.kKZEsnbB.png",L="/assets/1460000021464592.Dnx799Yp.png",T="/assets/1460000021464589.XSLwXqgx.png",E="/assets/1460000021464593.e1MqigQ1.png",Q=JSON.parse('{"title":"索引失效的场景","description":"","frontmatter":{"title":"索引失效的场景"},"headers":[],"relativePath":"doc/数据库/Mysql/面试总结/索引失效/索引失效的场景.md","filePath":"packages/doc/src/数据库/Mysql/面试总结/索引失效/索引失效的场景.md","lastUpdated":1711622925000}'),P={name:"doc/数据库/Mysql/面试总结/索引失效/索引失效的场景.md"},A={id:"frontmatter-title",tabindex:"-1"},D=s("a",{class:"header-anchor",href:"#frontmatter-title","aria-label":'Permalink to "{{ $frontmatter.title }}"'},"​",-1),z=i('<p>索引对于MySQL而言，是非常重要的篇章。索引知识点也巨多，要想掌握透彻，需要逐个知识点一一击破，今天来先来聊聊哪些情况下会导致索引失效。</p><h2 id="图片总结版" tabindex="-1">图片总结版 <a class="header-anchor" href="#图片总结版" aria-label="Permalink to &quot;图片总结版&quot;">​</a></h2><p><img src="'+t+'" alt="索引失效的情况"></p><h2 id="全值匹配-索引最佳" tabindex="-1">全值匹配（索引最佳） <a class="header-anchor" href="#全值匹配-索引最佳" aria-label="Permalink to &quot;全值匹配（索引最佳）&quot;">​</a></h2><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>explain select * from user where name = &#39;zhangsan&#39; and age = 20 and pos = &#39;cxy&#39; and phone = &#39;18730658760&#39;;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p><img src="'+c+`" alt="索引失效的情况"></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>和索引顺序无关，MySQL底层的优化器会进行优化，调整索引的顺序</span></span>
<span class="line"><span>explain select * from user where name = &#39;zhangsan&#39; and age = 20 and pos = &#39;cxy&#39; and phone = &#39;18730658760&#39;;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p><img src="`+o+`" alt="索引失效的情况"></p><h2 id="_1、违反最左前缀法则" tabindex="-1">1、违反最左前缀法则 <a class="header-anchor" href="#_1、违反最左前缀法则" aria-label="Permalink to &quot;1、违反最左前缀法则&quot;">​</a></h2><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>如果索引有多列，要遵守最左前缀法则</span></span>
<span class="line"><span>即查询从索引的最左前列开始并且不跳过索引中的列</span></span>
<span class="line"><span>explain select * from user where age = 20 and phone = &#39;18730658760&#39; and pos = &#39;cxy&#39;;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p><img src="`+d+`" alt="索引失效的情况"></p><h2 id="_2、在索引列上做任何操作" tabindex="-1">2、在索引列上做任何操作 <a class="header-anchor" href="#_2、在索引列上做任何操作" aria-label="Permalink to &quot;2、在索引列上做任何操作&quot;">​</a></h2><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>如计算、函数、（自动or手动）类型转换等操作，会导致索引失效从而全表扫描</span></span>
<span class="line"><span>explain select * from user where left(name,5) = &#39;zhangsan&#39; and age = 20 and phone = &#39;18730658760&#39;;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p><img src="`+h+`" alt="索引失效的情况"></p><h2 id="_3、索引范围条件右边的列" tabindex="-1">3、索引范围条件右边的列 <a class="header-anchor" href="#_3、索引范围条件右边的列" aria-label="Permalink to &quot;3、索引范围条件右边的列&quot;">​</a></h2><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>索引范围条件右边的索引列会失效</span></span>
<span class="line"><span>explain select * from user where name = &#39;zhangsan&#39; and age &gt; 20 and pos = &#39;cxy&#39;;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p><img src="`+m+`" alt="索引失效的情况"></p><h2 id="_4、尽量使用覆盖索引" tabindex="-1">4、尽量使用覆盖索引 <a class="header-anchor" href="#_4、尽量使用覆盖索引" aria-label="Permalink to &quot;4、尽量使用覆盖索引&quot;">​</a></h2><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>只访问索引查询（索引列和查询列一致），减少select*</span></span>
<span class="line"><span>explain select name,age,pos,phone from user where age = 20;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p><img src="`+b+`" alt="索引失效的情况"></p><h2 id="_5、使用不等于-、" tabindex="-1">5、使用不等于（!=、&lt;&gt;） <a class="header-anchor" href="#_5、使用不等于-、" aria-label="Permalink to &quot;5、使用不等于（!=、&lt;&gt;）&quot;">​</a></h2><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>mysql在使用不等于（!=、&lt;&gt;）的时候无法使用索引会导致全表扫描（除覆盖索引外）</span></span>
<span class="line"><span>explain select * from user where age != 20;</span></span>
<span class="line"><span>explain select * from user where age &lt;&gt; 20;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p><img src="`+u+'" alt="索引失效的情况"></p><p><img src="'+g+`" alt="索引失效的情况"></p><h2 id="_6、like以通配符开头-abc" tabindex="-1">6、like以通配符开头（&#39;%abc&#39;） <a class="header-anchor" href="#_6、like以通配符开头-abc" aria-label="Permalink to &quot;6、like以通配符开头（&#39;%abc&#39;）&quot;">​</a></h2><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>索引失效</span></span>
<span class="line"><span>explain select * from user where name like &#39;%zhangsan&#39;;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p><img src="`+v+`" alt="索引失效的情况"></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>索引生效</span></span>
<span class="line"><span>explain select * from user where name like &#39;zhangsan%&#39;;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p><img src="`+_+'" alt="索引失效的情况"></p><h2 id="_7、隐式类型转换" tabindex="-1">7、隐式类型转换 <a class="header-anchor" href="#_7、隐式类型转换" aria-label="Permalink to &quot;7、隐式类型转换&quot;">​</a></h2><p>链接：<a href="https://www.cnblogs.com/guitu18/p/12113495.html" target="_blank" rel="noreferrer">https://www.cnblogs.com/guitu18/p/12113495.html</a></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>explain select * from user where name = 2000;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p><img src="'+k+`" alt="索引失效的情况"></p><ol><li>当操作符<strong>左右两边的数据类型不一致</strong>时，会发生<strong>隐式转换</strong>。</li><li>当where查询操作符<strong>左边为数值类型</strong>时发生了隐式转换，那么对效率影响不大，但还是不推荐这么做。</li><li>当where查询操作符<strong>左边为字符类型</strong>时发生了隐式转换，那么会导致索引失效，造成全表扫描效率极低。</li><li>字符串转换为数值类型时，非数字开头的字符串会转化为<code>0</code>，以数字开头的字符串会截取从第一个字符到第一个非数字内容为止的值为转化结果。</li></ol><h2 id="_8、or连接" tabindex="-1">8、or连接 <a class="header-anchor" href="#_8、or连接" aria-label="Permalink to &quot;8、or连接&quot;">​</a></h2><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>少用or</span></span>
<span class="line"><span>explain select * from user where name = &#39;2000&#39; or age = 20 or pos =&#39;cxy&#39;;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p><img src="`+y+`" alt="索引失效的情况"></p><h2 id="_9、order-by" tabindex="-1">9、order by <a class="header-anchor" href="#_9、order-by" aria-label="Permalink to &quot;9、order by&quot;">​</a></h2><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>正常（索引参与了排序）</span></span>
<span class="line"><span>explain select * from user where name = &#39;zhangsan&#39; and age = 20 order by age,pos;</span></span>
<span class="line"><span>备注：索引有两个作用：排序和查找</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p><img src="`+f+`" alt="索引失效的情况"></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>导致额外的文件排序（会降低性能）</span></span>
<span class="line"><span>explain select name,age from user where name = &#39;zhangsan&#39; order by pos;//违反最左前缀法则</span></span>
<span class="line"><span>explain select name,age from user where name = &#39;zhangsan&#39; order by pos,age;//违反最左前缀法则</span></span>
<span class="line"><span>explain select * from user where name = &#39;zhangsan&#39; and age = 20 order by created_time,age;//含非索引字段</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p><img src="`+w+'" alt="索引失效的情况"></p><p><img src="'+x+'" alt="索引失效的情况"></p><p><img src="'+C+`" alt="索引失效的情况"></p><h2 id="_10、group-by" tabindex="-1">10、group by <a class="header-anchor" href="#_10、group-by" aria-label="Permalink to &quot;10、group by&quot;">​</a></h2><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>正常（索引参与了排序）</span></span>
<span class="line"><span>explain select name,age from user where name = &#39;zhangsan&#39; group by age;</span></span>
<span class="line"><span>备注：分组之前必排序（排序同order by）</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p><img src="`+q+`" alt="索引失效的情况"></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>导致产生临时表（会降低性能）</span></span>
<span class="line"><span>explain select name,pos from user where name = &#39;zhangsan&#39; group by pos;//违反最左前缀法则</span></span>
<span class="line"><span>explain select name,age from user where name = &#39;zhangsan&#39; group by pos,age;//违反最左前缀法则</span></span>
<span class="line"><span>explain select name,age from user where name = &#39;zhangsan&#39; group by age,created_time;//含非索引字段</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p><img src="`+L+'" alt="索引失效的情况"></p><p><img src="'+T+'" alt="索引失效的情况"></p><p><img src="'+E+'" alt="索引失效的情况"></p><h2 id="使用的示例数据" tabindex="-1">使用的示例数据 <a class="header-anchor" href="#使用的示例数据" aria-label="Permalink to &quot;使用的示例数据&quot;">​</a></h2><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>mysql&gt; show create table user \\G</span></span>\n<span class="line"><span>******************************************************</span></span>\n<span class="line"><span>       Table: user</span></span>\n<span class="line"><span>Create Table: CREATE TABLE `user` (</span></span>\n<span class="line"><span>  `id` int(10) NOT NULL AUTO_INCREMENT,</span></span>\n<span class="line"><span>  `name` varchar(20) DEFAULT NULL,</span></span>\n<span class="line"><span>  `age` int(10) DEFAULT &#39;0&#39;,</span></span>\n<span class="line"><span>  `pos` varchar(30) DEFAULT NULL,</span></span>\n<span class="line"><span>  `phone` varchar(11) DEFAULT NULL,</span></span>\n<span class="line"><span>  `created_time` datetime DEFAULT NULL,</span></span>\n<span class="line"><span>  PRIMARY KEY (`id`),</span></span>\n<span class="line"><span>  KEY `idx_name_age_pos_phone` (`name`,`age`,`pos`,`phone`)</span></span>\n<span class="line"><span>) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br></div></div>',53);function N(a,U,M,S,B,F){return r(),e("div",null,[s("h1",A,[p(l(a.$frontmatter.title)+" ",1),D]),z])}const R=n(P,[["render",N]]);export{Q as __pageData,R as default};
